from typing import Any

def _stripe_error(resp: requests.Response) -> dict[str, Any]:
    """Convert a non-2xx Stripe response to a structured error dict."""
    try:
        body = resp.json()
        stripe_err = body.get("error", {})
        message = stripe_err.get("message", resp.text)
        code = stripe_err.get("code", "unknown")
    except Exception:
        message = resp.text
        code = "parse_error"

    status = resp.status_code
    if status in (401, 403):
        error_type = "PERMISSION_DENIED"
    elif status == 404:
        error_type = "NOT_FOUND"
    elif status == 429:
        retry_after = resp.headers.get("Retry-After", "unknown")
        return {"error": "RATE_LIMITED", "message": message,
                "retry_after_seconds": retry_after}
    elif status == 409:
        error_type = "CONFLICT"
    elif status >= 500:
        error_type = "SERVICE_UNAVAILABLE"
    else:
        error_type = "VALIDATION_ERROR"

    return {"error": error_type, "message": message, "stripe_code": code}

def get_stripe_customer(customer_id: str) -> dict[str, Any]:
    """Look up a Stripe customer by ID."""
    if not customer_id.startswith("cus_"):
        return {"error": "VALIDATION_ERROR",
                "message": "customer_id must start with 'cus_'"}

    resp = _STRIPE.get(
        f"{_STRIPE_BASE}/customers/{customer_id}",
        timeout=10,
    )
    if not resp.ok:
        return _stripe_error(resp)

    c = resp.json()
    return {
        "customer_id": c["id"],
        "email": c.get("email"),
        "name": c.get("name"),
        "currency": c.get("currency"),
        "created_at": c.get("created"),
        "delinquent": c.get("delinquent", False),
        "subscriptions": [
            {"id": s["id"], "status": s["status"], "plan": s["plan"]["nickname"]}
            for s in c.get("subscriptions", {}).get("data", [])
        ],
    }

_SUPPORTED_CURRENCIES = {"usd", "eur", "gbp", "jpy", "cad", "aud"}

def create_payment_intent(
    amount_cents: int,
    currency: str,
    customer_id: str | None = None,
    description: str = "",
) -> dict[str, Any]:
    """Create a Stripe payment intent."""
    if amount_cents < 50:
        return {"error": "VALIDATION_ERROR",
                "message": "amount_cents must be >= 50 (Stripe minimum)"}
    currency = currency.lower()
    if currency not in _SUPPORTED_CURRENCIES:
        return {"error": "VALIDATION_ERROR",
                "message": f"currency must be one of {sorted(_SUPPORTED_CURRENCIES)}"}

    payload: dict[str, Any] = {
        "amount": amount_cents,
        "currency": currency,
        "automatic_payment_methods": {"enabled": "true"},
    }
    if customer_id:
        if not customer_id.startswith("cus_"):
            return {"error": "VALIDATION_ERROR",
                    "message": "customer_id must start with 'cus_'"}
        payload["customer"] = customer_id
    if description:
        payload["description"] = description[:500]   # Stripe max

    resp = _STRIPE.post(
        f"{_STRIPE_BASE}/payment_intents",
        data=payload,
        timeout=15,
    )
    if not resp.ok:
        return _stripe_error(resp)

    pi = resp.json()
    return {
        "payment_intent_id": pi["id"],
        "client_secret": pi["client_secret"],
        "status": pi["status"],
        "amount_cents": pi["amount"],
        "currency": pi["currency"],
    }

def list_stripe_invoices(
    customer_id: str,
    limit: int = 10,
    starting_after: str | None = None,
) -> dict[str, Any]:
    """List invoices for a customer. Use starting_after for pagination."""
    if not 1 <= limit <= 100:
        return {"error": "VALIDATION_ERROR",
                "message": "limit must be 1–100"}

    params: dict[str, Any] = {
        "customer": customer_id,
        "limit": limit,
        "expand[]": "data.subscription",
    }
    if starting_after:
        params["starting_after"] = starting_after

    resp = _STRIPE.get(f"{_STRIPE_BASE}/invoices", params=params, timeout=10)
    if not resp.ok:
        return _stripe_error(resp)

    body = resp.json()
    invoices = body.get("data", [])
    return {
        "invoices": [
            {
                "invoice_id": inv["id"],
                "amount_due": inv["amount_due"],
                "currency": inv["currency"],
                "status": inv["status"],
                "created_at": inv["created"],
            }
            for inv in invoices
        ],
        "has_more": body.get("has_more", False),
        "next_cursor": invoices[-1]["id"] if body.get("has_more") and invoices else None,
    }
